import{_ as t,o as a,c as o,ag as d}from"./chunks/framework.DTiDeF2Q.js";const m=JSON.parse('{"title":"Алиасы Modern Tooling: замены Unix на базе Rust | Dotfiles (RU)","titleTemplate":":title","description":"Современные shell-алиасы для eza, bat и ripgrep. Замените устаревшие Unix-инструменты более быстрыми альтернативами на Rust.","frontmatter":{"title":"Алиасы Modern Tooling: замены Unix на базе Rust","description":"Современные shell-алиасы для eza, bat и ripgrep. Замените устаревшие Unix-инструменты более быстрыми альтернативами на Rust.","lang":"ru-RU","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Алиасы Modern Tooling: замены Unix на базе Rust preview","canonical":"/ru/aliases/modern/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Алиасы Modern Tooling: замены Unix на базе Rust","pageType":"docs","schemaType":"WebPage","metaTitle":"Алиасы Modern Tooling | Dotfiles","permalink":"/ru/aliases/modern/","sidebar":true,"meta":[{"name":"keywords","content":"modern алиасы, eza, bat, ripgrep, rust cli инструменты, dotfiles, shell"},{"name":"twitter:card","content":"summary"},{"name":"twitter:title","content":"Алиасы Modern Tooling | Dotfiles"},{"name":"twitter:description","content":"Современные shell-алиасы для eza, bat и ripgrep. Замените устаревшие Unix-инструменты альтернативами на Rust."},{"name":"og:title","content":"Алиасы Modern Tooling | Dotfiles"},{"name":"og:description","content":"Современные shell-алиасы для eza, bat и ripgrep. Замените устаревшие Unix-инструменты альтернативами на Rust."},{"name":"og:image:alt","content":"Dotfiles - Simply designed to fit your shell life"},{"name":"og:locale","content":"ru_RU"}]},"headers":[],"relativePath":"ru/aliases/modern/index.md","filePath":"ru/aliases/modern/index.md","lastUpdated":1773010926000}'),r={name:"ru/aliases/modern/index.md"};function i(n,e,l,c,s,h){return a(),o("div",null,[...e[0]||(e[0]=[d('<h1 id="алиасы-modern-tooling" tabindex="-1">Алиасы Modern Tooling <a class="header-anchor" href="#алиасы-modern-tooling" aria-label="Permalink to &quot;Алиасы Modern Tooling&quot;">​</a></h1><p>Более быстрые и умные замены для устаревших Unix-команд.</p><h2 id="обзор" tabindex="-1">Обзор <a class="header-anchor" href="#обзор" aria-label="Permalink to &quot;Обзор&quot;">​</a></h2><p>Алиасы modern, определённые в <code>modern.aliases.sh</code>, предоставляют альтернативы на базе Rust традиционным Unix-инструментам. Эти алиасы загружаются автоматически <code>chezmoi</code> и корректно откатываются к стандартным командам, когда современные инструменты недоступны.</p><h2 id="справочник" tabindex="-1">Справочник <a class="header-anchor" href="#справочник" aria-label="Permalink to &quot;Справочник&quot;">​</a></h2><h3 id="список-фаилов-с-eza" tabindex="-1">Список файлов с eza <a class="header-anchor" href="#список-фаилов-с-eza" aria-label="Permalink to &quot;Список файлов с eza&quot;">​</a></h3><p>Заменяет <code>ls</code> при установленном <code>eza</code>.</p><table tabindex="0"><thead><tr><th>Алиас</th><th>Команда</th><th>Описание</th></tr></thead><tbody><tr><td><code>ls</code></td><td><code>eza --icons</code></td><td>Список файлов с иконками</td></tr><tr><td><code>ll</code></td><td><code>eza -alF</code></td><td>Длинный формат списка</td></tr><tr><td><code>la</code></td><td><code>eza -a</code></td><td>Список всех файлов, включая скрытые</td></tr><tr><td><code>lt</code></td><td><code>eza --tree</code></td><td>Отобразить дерево каталогов</td></tr></tbody></table><p>Откатывается к стандартному <code>ls</code>, если <code>eza</code> не установлен.</p><h3 id="содержимое-фаилов-с-bat" tabindex="-1">Содержимое файлов с bat <a class="header-anchor" href="#содержимое-фаилов-с-bat" aria-label="Permalink to &quot;Содержимое файлов с bat&quot;">​</a></h3><p>Заменяет <code>cat</code> при установленном <code>bat</code>.</p><table tabindex="0"><thead><tr><th>Алиас</th><th>Команда</th><th>Описание</th></tr></thead><tbody><tr><td><code>cat</code></td><td><code>bat</code></td><td>Показать содержимое файла с подсветкой синтаксиса</td></tr></tbody></table><h3 id="поиск-с-ripgrep" tabindex="-1">Поиск с ripgrep <a class="header-anchor" href="#поиск-с-ripgrep" aria-label="Permalink to &quot;Поиск с ripgrep&quot;">​</a></h3><p>Заменяет <code>grep</code> при установленном <code>rg</code>.</p><table tabindex="0"><thead><tr><th>Алиас</th><th>Команда</th><th>Описание</th></tr></thead><tbody><tr><td><code>grep</code></td><td><code>rg</code></td><td>Поиск в содержимом файлов с Ripgrep</td></tr></tbody></table>',15)])])}const b=t(r,[["render",i]]);export{m as __pageData,b as default};
